import{_ as a,o as t,c as i,a2 as o}from"./chunks/framework.OWFDNrRT.js";const u=JSON.parse('{"title":"Modding DX/UX Reference Analysis","description":"","frontmatter":{},"headers":[],"relativePath":"reference/MODDING-DX-REFERENCE.md","filePath":"reference/MODDING-DX-REFERENCE.md","lastUpdated":1773460793000}'),r={name:"reference/MODDING-DX-REFERENCE.md"};function n(s,e,l,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="modding-dx-ux-reference-analysis" tabindex="-1">Modding DX/UX Reference Analysis <a class="header-anchor" href="#modding-dx-ux-reference-analysis" aria-label="Permalink to &quot;Modding DX/UX Reference Analysis&quot;">​</a></h1><p><strong>Date</strong>: 2026-03-09 <strong>Purpose</strong>: Reference games and patterns to emulate for DINOForge modding library design.</p><hr><h2 id="tier-1-best-official-modding-dx" tabindex="-1">Tier 1: Best Official Modding DX <a class="header-anchor" href="#tier-1-best-official-modding-dx" aria-label="Permalink to &quot;Tier 1: Best Official Modding DX&quot;">​</a></h2><h3 id="factorio" tabindex="-1">Factorio <a class="header-anchor" href="#factorio" aria-label="Permalink to &quot;Factorio&quot;">​</a></h3><p><strong>Copy</strong>: API shape, manifests, dependency/version handling, distribution, contract discipline.</p><ul><li>Documented API with stable contract</li><li>Official mod portal with in-ecosystem distribution</li><li>Explicit publish/upload APIs</li><li>Modder workflow: &quot;author against a known contract, package, publish, update&quot;</li><li>Not &quot;hack files until it works&quot;</li></ul><h3 id="minecraft-bedrock-add-ons" tabindex="-1">Minecraft Bedrock Add-Ons <a class="header-anchor" href="#minecraft-bedrock-add-ons" aria-label="Permalink to &quot;Minecraft Bedrock Add-Ons&quot;">​</a></h3><p><strong>Copy</strong>: Pack structure, capability declarations, folder conventions.</p><ul><li>Resource packs + behavior packs + manifest structure</li><li>Content organization that makes generation and validation easy</li><li>Machine-readable pack schemas</li></ul><h3 id="bethesda-creation-kit" tabindex="-1">Bethesda Creation Kit <a class="header-anchor" href="#bethesda-creation-kit" aria-label="Permalink to &quot;Bethesda Creation Kit&quot;">​</a></h3><p><strong>Copy</strong>: Editor-centric world/content creation, asset authoring pipelines.</p><ul><li>&quot;Ship an editor and treat mods as first-class data packages&quot;</li><li>Historically strongest mod ecosystems</li></ul><h3 id="uefn-roblox-creator-stack" tabindex="-1">UEFN / Roblox Creator Stack <a class="header-anchor" href="#uefn-roblox-creator-stack" aria-label="Permalink to &quot;UEFN / Roblox Creator Stack&quot;">​</a></h3><p><strong>Copy</strong>: End-to-end creation pipeline concept (editor, scripting, assets, testing, publishing, docs, discoverability).</p><ul><li>Not classic modding but best modern creator DX</li><li>Creation treated as full pipeline</li></ul><hr><h2 id="tier-2-best-community-rescued-dx" tabindex="-1">Tier 2: Best Community-Rescued DX <a class="header-anchor" href="#tier-2-best-community-rescued-dx" aria-label="Permalink to &quot;Tier 2: Best Community-Rescued DX&quot;">​</a></h2><h3 id="satisfactory-sml-smm" tabindex="-1">Satisfactory + SML/SMM <a class="header-anchor" href="#satisfactory-sml-smm" aria-label="Permalink to &quot;Satisfactory + SML/SMM&quot;">​</a></h3><p><strong>Copy</strong>: Mod loaders, plugin bootstrap, community tooling, install/dependency UX.</p><ul><li>Satisfactory Mod Manager makes install smooth</li><li>SML docs cover dev environment setup</li><li>Relevant because DINOForge lives in same world: semi-official feeling, layered over shipped game</li></ul><h3 id="rimworld-harmony" tabindex="-1">RimWorld + Harmony <a class="header-anchor" href="#rimworld-harmony" aria-label="Permalink to &quot;RimWorld + Harmony&quot;">​</a></h3><p><strong>Copy</strong>: Split between declarative content and imperative code patches.</p><ul><li>XML-heavy approach + C#/Harmony extension</li><li>Easy things are data, hard things are code, invasive things are patch-based</li><li>Critical conceptual model for DINOForge</li></ul><h3 id="unity-bepinex-thunderstore-ecosystems" tabindex="-1">Unity/BepInEx/Thunderstore Ecosystems <a class="header-anchor" href="#unity-bepinex-thunderstore-ecosystems" aria-label="Permalink to &quot;Unity/BepInEx/Thunderstore Ecosystems&quot;">​</a></h3><p><strong>Copy</strong>: Reality of mod loaders on shipped Unity games.</p><ul><li>Cities: Skylines II community stack</li><li>More &quot;effective&quot; than elegant but proven</li></ul><hr><h2 id="key-design-patterns-to-steal" tabindex="-1">Key Design Patterns to Steal <a class="header-anchor" href="#key-design-patterns-to-steal" aria-label="Permalink to &quot;Key Design Patterns to Steal&quot;">​</a></h2><h3 id="_1-stable-package-shape" tabindex="-1">1. Stable Package Shape <a class="header-anchor" href="#_1-stable-package-shape" aria-label="Permalink to &quot;1. Stable Package Shape&quot;">​</a></h3><p>Every mod has manifest, declared version, dependencies, predictable folder layout.</p><h3 id="_2-declarative-first-authoring" tabindex="-1">2. Declarative-First Authoring <a class="header-anchor" href="#_2-declarative-first-authoring" aria-label="Permalink to &quot;2. Declarative-First Authoring&quot;">​</a></h3><p>Most mods are data edits: content packs, stat changes, loot tables, spawn rules, UI definitions, config bundles.</p><h3 id="_3-code-only-for-hard-cases" tabindex="-1">3. Code Only for Hard Cases <a class="header-anchor" href="#_3-code-only-for-hard-cases" aria-label="Permalink to &quot;3. Code Only for Hard Cases&quot;">​</a></h3><p>Narrow surface: event hooks, patch points, extension interfaces, ECS system registration, custom components.</p><h3 id="_4-one-click-install-update" tabindex="-1">4. One-Click Install/Update <a class="header-anchor" href="#_4-one-click-install-update" aria-label="Permalink to &quot;4. One-Click Install/Update&quot;">​</a></h3><p>If system requires dragging DLLs into mystery folders, UX is already mediocre.</p><h3 id="_5-validation-before-runtime" tabindex="-1">5. Validation Before Runtime <a class="header-anchor" href="#_5-validation-before-runtime" aria-label="Permalink to &quot;5. Validation Before Runtime&quot;">​</a></h3><p>Reduce &quot;launch game, crash, guess why.&quot; Lint manifests, dependency graphs, schema validity, asset references, ECS registration conflicts before game boots.</p><h3 id="_6-discoverability-and-docs-in-happy-path" tabindex="-1">6. Discoverability and Docs in Happy Path <a class="header-anchor" href="#_6-discoverability-and-docs-in-happy-path" aria-label="Permalink to &quot;6. Discoverability and Docs in Happy Path&quot;">​</a></h3><p>Docs part of workflow, not buried in Discord archaeology.</p><hr><h2 id="what-not-to-copy" tabindex="-1">What NOT to Copy <a class="header-anchor" href="#what-not-to-copy" aria-label="Permalink to &quot;What NOT to Copy&quot;">​</a></h2><ul><li>Raw BepInEx &quot;drop DLL in plugins and pray&quot;</li><li>Undocumented patch soup</li><li>Hidden load order rules</li><li>Mods defined by arbitrary code instead of typed schemas</li><li>Asset imports with no validation</li><li>Discord-as-documentation</li></ul><hr><h2 id="dinoforge-hybrid-model" tabindex="-1">DINOForge Hybrid Model <a class="header-anchor" href="#dinoforge-hybrid-model" aria-label="Permalink to &quot;DINOForge Hybrid Model&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Source</th></tr></thead><tbody><tr><td>API shape, manifests, versioning</td><td>Factorio</td></tr><tr><td>Declarative content + code escape hatch</td><td>RimWorld</td></tr><tr><td>Mod loaders, plugin bootstrap</td><td>Satisfactory/BepInEx</td></tr><tr><td>Pack schemas, folder conventions</td><td>Minecraft Bedrock</td></tr><tr><td>End-to-end pipeline concept</td><td>UEFN/Roblox</td></tr></tbody></table><hr><h2 id="agentic-modding-pipeline-from-star-wars-conversation" tabindex="-1">Agentic Modding Pipeline (from Star Wars Conversation) <a class="header-anchor" href="#agentic-modding-pipeline-from-star-wars-conversation" aria-label="Permalink to &quot;Agentic Modding Pipeline (from Star Wars Conversation)&quot;">​</a></h2><p>The scaffold converts natural-language requests into a deterministic build pipeline:</p><ol><li><strong>Request -&gt; Typed Mod Spec</strong> (machine-validated contract, not loose prompt)</li><li><strong>Orchestrator</strong> spawns specialist agents</li><li><strong>Game Adapter</strong> handles per-game inspection, loader, asset discovery, patching</li><li><strong>Universe Pack</strong> encodes faction taxonomies, era rules, naming/style guides</li><li><strong>Asset Pipeline</strong> handles discovery, permission checking, generation, conversion</li><li><strong>Validation</strong> checks completeness, coherence, stability, packaging</li><li><strong>Recipe Library</strong> provides reusable recipes (replace unit family, add hero, retheme buildings)</li><li><strong>Knowledge Base</strong> provides persistent queryable knowledge for game systems, prior mods, style guides</li></ol><h3 id="quality-formula" tabindex="-1">Quality Formula <a class="header-anchor" href="#quality-formula" aria-label="Permalink to &quot;Quality Formula&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>quality = model capability x process maturity x tool coverage x knowledge depth x validation rigor x library depth</span></span></code></pre></div><p>Once model is &quot;good enough,&quot; dominant terms are process, library, validation, tools.</p>',54)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
